        <button onclick="appendNumber(2)">2</button>
        <button onclick="appendNumber(3)">3</button>
        <button onclick="appendOperator('+')">+</button>
        <button onclick="appendNumber(0)" style="width: calc(67% - 4px);">0</button>
        <button onclick="appendDecimalPoint()">.</button>
        <button onclick="calculateResult()" style="width: calc(33.3% - 4px);">=</button>
    </div>

    <script>
        function clearDisplay() {
            document.getElementById('display').value = '';
        }

        function deleteDigit() {
            let display = document.getElementById('display');
            display.value = display.value.slice(0, -1);
        }

        function appendNumber(number) {
            document.getElementById('display').value += number;
        }

        function appendOperator(operator) {
            document.getElementById('display').value += operator;
        }

        function appendDecimalPoint() {
            let display = document.getElementById('display');
            if (display.value.includes('.')) return; // Prevent multiple decimal points
            display.value += '.';
        }

        function calculateResult() {
            try {
                let result = eval(document.getElementById('display').value);
                document.getElementById('display').value = result;
            } catch (error) {
                document.getElementById('display').value = 'Error';
            }
        }
    </script>
</body>
